Use ASP.NET Core's **`WebApplicationFactory<T>`** — it creates an in-memory test server and gives you an `HttpClient` that talks to it over HTTP without binding to a real port.

**Setup (xUnit example):**

```csharp
// 1. Add these NuGet packages to your test project:
//    Microsoft.AspNetCore.Mvc.Testing
//    xunit

// 2. Create a fixture
public class McpServerTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpServerTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` hosts your app in-process using `TestServer`.
- **Full pipeline** — middleware, routing, DI, serialization all run exactly as in production.
- **Mock dependencies** by overriding `WebApplicationFactory.ConfigureWebHost` to swap services (e.g., replace a database with an in-memory fake).
- If your MCP endpoint uses **SSE** (`text/event-stream`), use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the stream line-by-line.
- Make sure `Program` is accessible to the test project (add `InternalsVisibleTo` or a `public partial class Program { }` marker).
